-- DDL
CREATE DATABASE IF NOT EXISTS AB_TEST_DB;
USE DATABASE AB_TEST_DB;
CREATE SCHEMA IF NOT EXISTS RAW;
USE SCHEMA RAW;

CREATE OR REPLACE TABLE raw_experiment_events (
    borrower_id        VARCHAR,
    loan_balance       FLOAT,
    loan_status        VARCHAR,
    int_rate           FLOAT,
    debt_to_income     FLOAT,
    credit_score       FLOAT,
    annual_income      FLOAT,
    prior_delinquency  FLOAT,
    recovery_amount    FLOAT,
    state              VARCHAR,
    cohort_date        VARCHAR,
    experiment_group   VARCHAR,
    payment_made_flag  INT,
    rolled_to_severe   INT
);





















































